#include <stdio.h>
#include <stdlib.h>
#define MAX 1000
int max(int a, int b) { return a > b ? a : b; }
int main() {
    int T, N, M;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &M);
        int **grid = (int **)malloc(N * sizeof(int *));
        for (int i = 0; i < N; i++) {
            grid[i] = (int *)malloc(M * sizeof(int));
            for (int j = 0; j < M; j++) {
                scanf("%d", &grid[i][j]);
            }
        }
        int maxCollect = 0;
        for (int i = 0; i < N; i++) {
            int collect = 0;
            int x = i, y = M - 1;
            collect += grid[x][y];
            // first left turn
            int firstTurn = -1;
            for (int j = M - 2; j >= 0; j--) {
                if (grid[x][j] > firstTurn) {
                    firstTurn = grid[x][j];
                    y = j;
                }
            }
            collect += firstTurn;
            // second left turn
            int secondTurn = -1;
            for (int j = x - 1; j >= 0; j--) {
                if (grid[j][y] > secondTurn) {
                    secondTurn = grid[j][y];
                }
            }
            collect += secondTurn;
            maxCollect = max(maxCollect, collect);
        }
        printf("%d\n", maxCollect);
        for (int i = 0; i < N; i++) {
            free(grid[i]);
        }
        free(grid);
    }
    return 0;
}

