            int maxCollect = 0;
            for (int i = 0; i < N; i++) {
                int collect = 0;
                int x = i, y = M - 1;
                collect += grid[x][y];
                // first left turn
                int firstTurn = -1;
                for (int j = M - 2; j >= 0; j--) {
                    if (grid[x][j] > firstTurn) {
                        firstTurn = grid[x][j];
                        y = j;
